import React from "react";
import "./Dashboard.css";

export default function ProfileMenu() {
  return (
    <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <div style={{ display: 'flex', gap: 32 }}>
        <a href="/dashboard" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Dashboard
        </a>
        <a href="/addnew" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Add New
        </a>
        <a href="#" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          History
        </a>
        <a href="#" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Tools
        </a>
      </div>
    </div>
  );
}
